class TestConflictingStateTransitions:
    """
    The specification forbids creation of a new patient record that would
    create conflicting state transitions (e.g. creating a record for an
    already-deceased patient, or re-activating a merged/deleted record).
    """

    def test_cannot_create_patient_for_deceased_record(
        self,
        patient_service,
        patient_repo,
        registered_clinician,
        valid_demographics,
    ):
        deceased = Patient(
            id=str(uuid.uuid4()),
            status=PatientStatus.DECEASED,
            **valid_demographics,
        )
        patient_repo.find_by_nhs_number.return_value = deceased
        with pytest.raises((DuplicateResourceError, InvalidStateTransitionError)):
            patient_service.create_patient(
                requester=registered_clinician, demographics=valid_demographics
            )

    def test_cannot_create_patient_for_merged_record(
        self,
        patient_service,
