        patient_repo.find_by_nhs_number.return_value = merged
        with pytest.raises((DuplicateResourceError, InvalidStateTransitionError)):
            patient_service.create_patient(
                requester=registered_clinician, demographics=valid_demographics
            )

    def test_cannot_create_patient_for_deleted_record(
        self,
        patient_service,
