class TestIdempotencyAndConcurrency:
    def test_concurrent_duplicate_creation_is_rejected(
        self,
        patient_service,
        patient_repo,
        registered_clinician,
        valid_demographics,
    ):
        """
        Simulates a race where the first call succeeds but the second,
        arriving after the repo confirms a duplicate, must be rejected.
        """
        created_patient = Patient(
            id=str(uuid.uuid4()),
            status=PatientStatus.ACTIVE,
            **valid_demographics,
        )
        # First call: no duplicate yet → saves successfully.
        patient_repo.find_by_nhs_number.return_value = None
        patient_service.create_patient(
            requester=registered_clinician, demographics=valid_demographics
        )

        # Second call: duplicate now present.
        patient_repo.find_by_nhs_number.return_value = created_patient
        with pytest.raises(DuplicateResourceError):
            patient_service.create_patient(
                requester=registered_clinician, demographics=valid_demographics
            )

    def test_idempotency_key_prevents_double_creation(
        self,
        patient_service,
        patient_repo,
        registered_clinician,
        valid_demographics,
    ):
        """
        If the service supports an idempotency key, a repeated request with
        the same key should return the original patient, not create a new one.
        """
        idempotency_key = str(uuid.uuid4())
        first = patient_service.create_patient(
            requester=registered_clinician,
            demographics=valid_demographics,
            idempotency_key=idempotency_key,
        )

        # Repository now returns the first patient for any subsequent look-up.
        patient_repo.find_by_nhs_number.return_value = first

        second = patient_service.create_patient(
            requester=registered_clinician,
            demographics=valid_demographics,
            idempotency_key=idempotency_key,
        )
        assert first.id == second.id
        # save should only have been called once
        patient_repo.save.assert_called_once()


